def load_json_safe(path: Path) -> Optional[Dict[str, Any]]:
    """Load JSON file safely, return None if not found or invalid."""
    if not path.exists():
        return None
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except (json.JSONDecodeError, IOError):
        return None


def validate_type(value: Any, expected_type: str, path: str = "") -> bool:
    """Validate that a value matches the expected JSON Schema type."""
    type_map = {
        "string": str,
        "number": (int, float),
        "integer": int,
        "boolean": bool,
        "array": list,
        "object": dict,
        "null": type(None)
    }
    
    if expected_type not in type_map:
        return False
    
    expected = type_map[expected_type]
    if isinstance(expected, tuple):
        return isinstance(value, expected)
    return isinstance(value, expected)


def validate_schema(data: Any, schema: Dict[str, Any], path: str = "") -> List[str]:
    """Recursively validate data against a JSON Schema definition."""
    errors = []
    
    # Check type
    if "type" in schema:
        if not validate_type(data, schema["type"], path):
            errors.append(f"{path}: Expected type '{schema['type']}', got {type(data).__name__}")
            return errors  # Can't validate further if type is wrong
    
    # Check object properties
    if schema.get("type") == "object" and isinstance(data, dict):
        # Check required fields
        if "required" in schema:
            for req_field in schema["required"]:
                if req_field not in data:
                    errors.append(f"{path}: Missing required field '{req_field}'")
        
        # Validate properties
        if "properties" in schema:
            for prop_name, prop_schema in schema["properties"].items():
                if prop_name in data:
                    prop_path = f"{path}.{prop_name}" if path else prop_name
                    errors.extend(validate_schema(data[prop_name], prop_schema, prop_path))
    
    # Check array items
    if schema.get("type") == "array" and isinstance(data, list):
        if "items" in schema:
            for i, item in enumerate(data):
                item_path = f"{path}[{i}]"
                errors.extend(validate_schema(item, schema["items"], item_path))
        
        # Check minItems
        if "minItems" in schema and len(data) < schema["minItems"]:
            errors.append(f"{path}: Array has {len(data)} items, minimum is {schema['minItems']}")
    
    # Check number constraints
    if schema.get("type") == "number" and isinstance(data, (int, float)):
        if "minimum" in schema and data < schema["minimum"]:
            errors.append(f"{path}: Value {data} is below minimum {schema['minimum']}")
        if "maximum" in schema and data > schema["maximum"]:
            errors.append(f"{path}: Value {data} is above maximum {schema['maximum']}")
    
    # Check integer constraints
    if schema.get("type") == "integer" and isinstance(data, int):
        if "minimum" in schema and data < schema["minimum"]:
            errors.append(f"{path}: Value {data} is below minimum {schema['minimum']}")
    
    return errors


class TestClusterResultsContract:
    """Contract tests for cluster results output schema (US3)."""

    @pytest.fixture(scope="class")
    def cluster_data(self) -> Optional[Dict[str, Any]]:
        """Load the cluster results file."""
        return load_json_safe(CLUSTER_RESULTS_PATH)

    def test_file_exists(self, cluster_data):
        """Test 1: Cluster results file must exist."""
        assert cluster_data is not None, f"Cluster results file not found at {CLUSTER_RESULTS_PATH}"

    def test_schema_structure(self, cluster_data):
        """Test 2: Validate full schema against contract (FR-005)."""
        errors = validate_schema(cluster_data, CLUSTER_CONTRACT)
        assert len(errors) == 0, f"Schema validation failed:\n" + "\n".join(errors)

    def test_jaccard_matrix_properties(self, cluster_data):
        """Test 3: Validate Jaccard matrix structure and values."""
        jaccard = cluster_data["jaccard_matrix"]
        tags = jaccard["tags"]
        matrix = jaccard["matrix"]

        # Check symmetry
        n = len(tags)
        assert len(matrix) == n, f"Matrix rows ({len(matrix)}) != tags count ({n})"
        for i, row in enumerate(matrix):
            assert len(row) == n, f"Row {i} length ({len(row)}) != tags count ({n})"
            for j, val in enumerate(row):
                assert 0.0 <= val <= 1.0, f"Jaccard value at [{i}][{j}] ({val}) out of range [0, 1]"
                if i != j:
                    # Check symmetry
                    assert math.isclose(matrix[i][j], matrix[j][i]), \
                        f"Jaccard matrix not symmetric at [{i}][{j}] vs [{j}][{i}]"

    def test_hierarchical_clustering_structure(self, cluster_data):
        """Test 4: Validate hierarchical clustering results."""
        hc = cluster_data["hierarchical_clustering"]
        
        # Check linkage matrix format (n-1 rows for n samples, 4 columns)
        linkage = hc["linkage_matrix"]
        assert len(linkage) > 0, "Linkage matrix is empty"
        for row in linkage:
            assert len(row) == 4, f"Linkage row has {len(row)} columns, expected 4"
            assert all(isinstance(x, (int, float)) for x in row), "Linkage row contains non-numeric values"
        
        # Check cluster assignments
        assignments = hc["cluster_assignments"]
        assert len(assignments) > 0, "Cluster assignments is empty"
        for cluster in assignments:
            assert "cluster_id" in cluster, "Missing cluster_id"
            assert "tags" in cluster, "Missing tags in cluster assignment"
            assert len(cluster["tags"]) > 0, "Cluster has no tags"

    def test_permutation_test_coherence(self, cluster_data):
        """Test 5: Validate permutation test results for cluster coherence (FR-005)."""
        perm = cluster_data["permutation_test"]
        
        # Required fields check (already done by schema, but be explicit)
        assert "observed_coherence" in perm, "Missing observed_coherence"
        assert "p_value" in perm, "Missing p_value"
        assert "is_significant" in perm, "Missing is_significant"
        
        # Validate coherence metric
        assert 0.0 <= perm["observed_coherence"] <= 1.0, \
            f"Observed coherence ({perm['observed_coherence']}) out of range [0, 1]"
        
        # Validate p-value
        assert 0.0 <= perm["p_value"] <= 1.0, \
            f"P-value ({perm['p_value']}) out of range [0, 1]"
        
        # Validate significance logic
        is_sig = perm["is_significant"]
        p_val = perm["p_value"]
        assert is_sig == (p_val < 0.05), \
            f"is_significant ({is_sig}) inconsistent with p_value ({p_val})"
        
        # Validate permutation count (FR-005: sufficient permutations)
        assert perm["n_permutations"] >= 100, \
            f"Number of permutations ({perm['n_permutations']}) < 100 (minimum for valid test)"

    def test_cluster_label_alignment_score(self, cluster_data):
        """Test 6: Validate Cluster Label Alignment Score (FR-008)."""
        score = cluster_data["cluster_label_alignment_score"]
        assert 0.0 <= score <= 1.0, \
            f"Alignment score ({score}) out of range [0, 1]"

    def test_intra_cluster_similarity(self, cluster_data):
        """Test 7: Validate intra-cluster similarity coefficient."""
        sim = cluster_data["intra_cluster_similarity"]
        assert 0.0 <= sim <= 1.0, \
            f"Intra-cluster similarity ({sim}) out of range [0, 1]"

    def test_metadata_completeness(self, cluster_data):
        """Test 8: Validate metadata fields."""
        meta = cluster_data["metadata"]
        assert "timestamp" in meta, "Missing timestamp"
        assert "total_tags" in meta, "Missing total_tags"
        assert "total_clusters" in meta, "Missing total_clusters"
        assert meta["total_tags"] > 0, "total_tags must be > 0"
        assert meta["total_clusters"] > 0, "total_clusters must be > 0"

    def test_permutation_test_specific_requirements(self, cluster_data):
        """Test 9: Specific FR-005 requirements for permutation test."""
        perm = cluster_data["permutation_test"]
        
        # Must have a method defined
        assert "method" in perm, "Permutation test missing 'method' field"
        assert perm["method"] in ["mean_coherence", "max_coherence", "median_coherence"], \
            f"Unknown permutation test method: {perm['method']}"
        
        # Must have null distribution stats
        assert "null_distribution_mean" in perm, "Missing null_distribution_mean"
        assert "null_distribution_std" in perm, "Missing null_distribution_std"
        
        # Null distribution std should be > 0 (otherwise test is invalid)
        assert perm["null_distribution_std"] > 0, \
            "Null distribution standard deviation must be > 0"